extra.modelCss:
/* Paleta simples e consistente */

:root {
  --bg: #0b0f19;
  --panel: #111827;
  --text: #e5e7eb;
  --muted: #9ca3af;
  --accent: #60a5fa;
  --border: rgba(255, 255, 255, 0.10);
}

body {
  background: var(--bg);
  color: var(--text);
}

.card {
  background: var(--panel);
  border: 1px solid var(--border);
  border-radius: 14px;
  padding: 16px;
}

.muted {
  color: var(--muted);
}

a {
  color: var(--accent);
}

/* Overlay com transparência */
.overlay {
  background: rgba(0, 0, 0, 0.5);
}
